sql:
SELECT time, battery_level
FROM telemetry_data
WHERE flight_id = 1;

SELECT aav_id, aav_name, aav_type, manufacturer, model_number
FROM aerial_vehicles
WHERE status = 'active';

SELECT COUNT(*) 
FROM flights 
WHERE pilot_id = 1 AND flight_duration > 10;

SELECT aerial_vehicles.aav_name, flights.start_time
FROM aerial_vehicles
JOIN flights ON aerial_vehicles.aav_id = flights.aav_id;

SELECT COUNT(*) 
FROM aerial_vehicles 
WHERE status = 'active';

SELECT aav_id
FROM aerial_vehicles
WHERE aav_id NOT IN (
    SELECT aav_id
    FROM flights
);

SELECT username, role, email
FROM users
WHERE user_id IN (SELECT DISTINCT pilot_id FROM flights);

external_knowledge:
- 'busiest' refers to the flight plan with the highest number of flights;
- 'carrying the most birds aloft in the skies' is a metaphor for having the most flights recorded in the database;
- 'flight plan' is a predefined route or schedule for flights.

sql:
SELECT DISTINCT u.username 
FROM users u
JOIN flights f ON u.user_id = f.pilot_id;
